INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00367', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲宅遭竊損失財物千萬元，案經轄區司法警察官乙、丙、丁調閱路口監視器畫面影像詳細查證比 對，顯示戊確實涉有重嫌，乙依法通知戊到場接受警詢，戊乃依乙通知指定之日時地點到場接受 警詢，警詢程序中，戊自始至終均矢口否認涉犯該起重大竊案。依據刑事訴訟法之相關規定，下 列敘述何者正確？', '["戊係依法通知到場應訊，警詢後應任由戊自由離去，不得將戊解送至該管檢察官複訊", "戊涉犯重大竊案，屬最輕本刑5年以上有期徒刑之罪，警詢後應將戊解送至該管檢察官複訊", "戊自始至終均矢口否認涉犯犯行，警詢後應將戊解送至該管檢察官複訊", "戊涉犯重大竊案，路口監視器畫面影像亦顯示戊確實涉有重嫌，警詢後應將戊解送至該管檢察 官複訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00368', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察機關實施通訊監察時，應嚴格遵守正當法律程序之要求，以免違法或不當侵害人民權益。 關於司法警察機關實施通訊監察之程序要求，下列敘述何者正確？', '["辦理通訊監察聲請案件，應由警察局刑警大隊偵查隊長或警察分局偵查隊長從嚴審核決行", "通訊監察執行期間，案件承辦人應至少每週派員取回監錄內容", "通訊監察執行期間，案件承辦人應至少每月作成一次以上之報告書陳報法院", "實施通訊監察之繼續監察期間，原則上不得逾一年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00369', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲、乙、丙三人依法逮捕搶奪罪之現行犯丁後，隨即帶回分局偵查隊進行警詢程序。 關於警詢程序之規範，下列敘述何者正確？', '["警詢時，應告知丁得隨時選任辯護人、輔佐人或代理人", "警詢時，丁若表示已選任辯護人時，應立即停止詢問。但有急迫情形且經記明筆錄者，不在此限", "警詢時，應全程連續錄音；必要時，並應全程連續錄影。但有急迫情形且經記明筆錄者，不在此限", "警詢時，丁不得請求對質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00370', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '某日17歲之少年丁因故持改造衝鋒槍朝某商店掃射，丁持槍掃射後隨即赴當地警察派出所自首， 由司法警察官甲、乙、丙三人負責詢問丁並製作警詢筆錄。關於甲、乙、丙三人詢問丁之程序規 範，下列敘述何者正確？', '["應先告知得選任辯護人", "應先告知得選任輔佐人", "經檢察官同意得於夜間詢問", "經法官同意得於夜間詢問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00371', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察人員實施偵查，必要時得於夜間執行搜索或扣押。關於司法警察人員於夜間執行搜索或 扣押之程序規範，下列敘述何者錯誤？', '["常用為組織犯罪行為之處所，得於夜間執行搜索或扣押", "常用為妨害風化行為之處所，得於夜間執行搜索或扣押", "搜索或扣押處所經住居人之承諾，得於夜間執行搜索或扣押", "假釋人住居或使用之處所，得於夜間執行搜索或扣押"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00372', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '所謂警察的意義，乃在闡明警察的本質、任務和手段；警察的本質係以法令為依據的行政作 用，警察的任務就是警察的目的，而警察的手段，係以下列何者為主要手段？', '["指導、服務、強制", "指導、協助、執行", "計畫、執行、督導", "任務、業務、勤務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00373', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '司法院大法官會議曾作出與警察權有關之解釋，下列何者正確？', '["釋字第588號解釋指出，憲法第8條第1項所稱「警察機關」，係泛指國家為維持公共安 全與秩序，必要時得對人民行使命令強制權力之實質警察機關", "釋字第570號解釋指出，警察法第9條之性質為具組織法之劃定職權與管轄事務之性質， 兼有具體權力措施的職權樣態", "釋字第491號解釋揭示之規範密度理論，對於警察權行使適用法律保留原則之程度，亦提 供重要的判斷標準", "釋字第445號解釋指出，警察勤務條例已非單純之組織法，實兼有行為法之性質，因此仍 可作為警察實施臨檢之作用依據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00374', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察人員依法令執行取締、盤查等勤務時，得依法使用警械。有關111年10月19日修正公 布之警械使用條例，下列敘述何者錯誤？', '["如有必要得命其停止舉動或高舉雙手，並檢查是否持有兇器。如遭抗拒，而有受到突擊之 虞時，得使用警械", "警察人員使用警械，致現場人員傷亡時，應迅速通報救護或送醫，並作必要之保護或戒護", "警察人員使用警械，其所屬機關接獲通報後，應進行調查並提供警察人員涉訟輔助及諮商 輔導", "法務部應遴聘相關機關（構）代表及專家學者組成調查小組，得依職權或依司法警察機關 之申請，就警察人員使用警械致人死亡或重傷爭議事件之使用時機、過程與相關行政責任 進行調查及提供意見"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00375', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關警察人員依據警察職權行使法及警械使用條例盤查可疑人，下列敘述何者錯誤？', '["警察於公共場所或合法進入之場所，得對合理懷疑其有犯罪之嫌疑或有犯罪之虞者，實施 查證身分", "盤查行經警察機關主管長官指定之公共場所、路段及管制站者，必須以防止犯罪，或處理 重大公共安全或社會秩序事件而有必要者為限", "警察人員執行盤查時，認犯罪嫌疑人或行為人有意圖奪取警察人員配槍或其他可能致人傷 亡之裝備機具，將危及警察人員或他人生命或身體時，得使用槍械逕行射擊", "警察人員執行盤查時，若受盤查人拒絕而逃逸，得使用槍械"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00376', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察遴選第三人蒐集資料經核准後，除最近2年內曾任第三人者外，應實施訓練，下列何者 非屬應訓練之內容？', '["防身術及緊急救護常識", "相關法律程序及法律責任", "狀況之處置", "蒐集資料之方法及技巧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
